// fenceRe matches ``` or ~~~ fenced openers whose info string starts with
// "codebase-". We don't fold ``` and ~~~ across a single doc intentionally.
fenceOpenRe = regexp.MustCompile("^(?P<fence>```+|~~~+)(codebase-[a-z-]+[^\\n]*)$")

ExtractOptions struct {
