docApi = createApi({
  reducerPath: 'docApi',
  baseQuery: fetchBaseQuery({ baseUrl: '/api' }),
  keepUnusedDataFor: 3600,
  endpoints: (b) => ({
    listDocs: b.query<PageMeta[], void>({ query: () => '/doc' }),
    getDoc: b.query<DocPage, string>({ query: (slug) => `/doc/${encodeURIComponent(slug)}` }),
  }),
})

indexApi = createApi({
  reducerPath: 'indexApi',
  baseQuery: fetchBaseQuery({ baseUrl: '/api' }),
  tagTypes: ['Index', 'Package', 'Symbol'],
  // Binary is immutable; aggressive cache is fine.
  keepUnusedDataFor: 3600,
  endpoints: (b) => ({
    getIndex: b.query<IndexSummary, void>({
      query: () => '/index',
      providesTags: ['Index'],
    }),
    getPackages: b.query<PackageLite[], void>({
      query: () => '/packages',
      providesTags: ['Package'],
    }),
    getSymbol: b.query<Symbol, string>({
      query: (id) => `/symbol/${encodeURIComponent(id)}`,
      providesTags: (_r, _e, id) => [{ type: 'Symbol', id }],
    }),
    searchSymbols: b.query<Symbol[], { q: string; kind?: string }>({
      query: ({ q, kind }) => `/search?q=${encodeURIComponent(q)}&kind=${kind ?? ''}`,
    }),
  }),
})

sourceApi = createApi({
  reducerPath: 'sourceApi',
  // Default query returns text; endpoints that need JSON override responseHandler.
  baseQuery: fetchBaseQuery({ baseUrl: '/api', responseHandler: 'text' }),
  keepUnusedDataFor: 3600,
  endpoints: (b) => ({
    getSource: b.query<string, string>({
      query: (path) => `/source?path=${encodeURIComponent(path)}`,
    }),
    getSnippet: b.query<string, { sym: string; kind?: SnippetKind }>({
      query: ({ sym, kind = 'declaration' }) =>
        `/snippet?sym=${encodeURIComponent(sym)}&kind=${kind}`,
    }),
    getSnippetRefs: b.query<SnippetRefView[], string>({
      query: (sym) => ({
        url: `/snippet-refs?sym=${encodeURIComponent(sym)}`,
        responseHandler: 'json',
      }),
    }),
    getSourceRefs: b.query<SourceRefView[], string>({
      query: (path) => ({
        url: `/source-refs?path=${encodeURIComponent(path)}`,
        responseHandler: 'json',
      }),
    }),
    getFileXref: b.query<FileXrefResponse, string>({
      query: (path) => ({
        url: `/file-xref?path=${encodeURIComponent(path)}`,
        responseHandler: 'json',
      }),
    }),
  }),
})

store = configureStore({
  reducer: {
    [indexApi.reducerPath]: indexApi.reducer,
    [sourceApi.reducerPath]: sourceApi.reducer,
    [docApi.reducerPath]: docApi.reducer,
    [xrefApi.reducerPath]: xrefApi.reducer,
  },
  middleware: (getDefault) =>
    getDefault().concat(
      indexApi.middleware,
      sourceApi.middleware,
      docApi.middleware,
      xrefApi.middleware,
    ),
})

xrefApi = createApi({
  reducerPath: 'xrefApi',
  baseQuery: fetchBaseQuery({ baseUrl: '/api' }),
  keepUnusedDataFor: 3600,
  endpoints: (b) => ({
    getXref: b.query<XrefResponse, string>({
      query: (id) => `/xref/${encodeURIComponent(id)}`,
    }),
  }),
})

