func dedent(s string) string {
	lines := strings.Split(s, "\n")
	prefix := -1
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		spaces := 0
		for _, c := range line {
			if c != ' ' && c != '\t' {
				break
			}
			spaces++
		}
		if prefix < 0 || spaces < prefix {
			prefix = spaces
		}
	}
	if prefix <= 0 {
		return s
	}
	for i, line := range lines {
		if len(line) >= prefix {
			lines[i] = line[prefix:]
		}
	}
	return strings.Join(lines, "\n")
}

