func safePath(p string) bool {
	if p == "" || strings.HasPrefix(p, "/") {
		return false
	}
	clean := path.Clean(p)
	if clean != p {
		return false
	}
	if strings.HasPrefix(clean, "..") || strings.Contains(clean, "/../") {
		return false
	}
	return true
}

