		data, err := fs.ReadFile(s.SPAFS, "index.html")
		if err != nil {
			http.Error(w, "SPA not built. Run 'go generate ./internal/web'.", http.StatusNotFound)
			return
		}
		writeSPA(w, "index.html", data)
	})
}

