          >
            {p.importPath.split('/').pop()}
            <div data-role="hint" style={{ fontSize: 11, color: 'var(--cb-color-muted)' }}>
              {p.importPath}
            </div>
          </a>
        </li>
      ))}
    </ul>
  );
}

