    return <div data-part={PARTS.empty}>No items</div>;
  }
  return (
    <ul data-part={PARTS.treeNav}>
      {items.map((item) => (
        <li key={item.id}>
          <a
            data-part={PARTS.treeNode}
            data-state={item.active ? 'active' : undefined}
            href={item.href}
            onClick={(e) => {
              if (item.onClick) {
                e.preventDefault();
                item.onClick();
              }
            }}
          >
            {item.label}
            {item.hint && <span data-role="hint"> ({item.hint})</span>}
          </a>
        </li>
      ))}
    </ul>
  );
}

